var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR001L0004: <color=#ffd34c>양하림</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. WR001L0004：<color=#ffd34c>ホシノ・ウサギ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR001L0004: <color=#ffd34c>楊夏琳</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข WR001L0004: <color=#ffd34c>ยัง ฮาริม</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số WR001L0004: <color=#ffd34c>Yang Harim</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. WR001L0004: <color=#ffd34c>杨夏琳</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. WR001L0004: <color=#ffd34c>Yang Harim</color>","FRA":"AEGIS 8\xA0PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. WR001L0004\xA0: <color=#ffd34c>Yang Harim</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하림이는 골목대장이었어요.","JPN":"ウサギは路地裏のボスでした。","ENG":"Harim was always the leader of the group.","TWN":"夏琳是這裡的孩子王。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"평범한 의미의 골목대장이 아니라...... 마을에 돌아다니던 동물들이 그 애를 엄청 따랐거든요.","JPN":"言葉通りの意味ではなく……町中の動物たちがあの子に懐いてたんです。","ENG":"And not just any ordinary leader. All of the animals in town really liked her.","TWN":"而且不是普通意義上的孩子王，就連遊蕩在村子裡的動物也很聽她的話。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"길고양이라던가 강아지라던가...... 하림이가 지나가기만 하면 모여들어서 주위를 맴돌았어요.","JPN":"野良猫や野良犬……ウサギが近くを通りかかると\\nどこからともなく彼女の周りに集まってくるんです。","ENG":"Such as stray cats and dogs... Whenever Harim passed by, they would all gather around her.","TWN":"不管是流浪貓還是狗……只要夏琳一經過，就會聚在她身邊，圍著她打轉。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래서 또래 아이들에게도 인기가 많았죠. 그 나이 때에는 다들 동물을 좋아하니까요.","JPN":"だから、同世代の子たちからも人気が\\nありました。動物が好きな年頃でもありますからね。","ENG":"That's why she was so popular amongst her friends as well. Everyone at that age loves animals.","TWN":"所以她在同齡的小孩中也很有人氣，畢竟那個年齡的小孩，大家都喜歡動物。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"좀 이상하단 생각은 들긴 했는데, 설마 하림이가 카운터일 줄은 몰랐죠.","JPN":"少しおかしいなとは思ったけど、まさか\\nウサギがカウンターだとは思いもしませんでした。","ENG":"It did seem weird at the time, we but had no idea Harim would be a Counter.","TWN":"雖然是覺得她有點怪，但誰知道夏琳竟然會是制裁者呢？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그걸 확신하게 된 계기가 있다면......","JPN":"でもそれを確信したきっかけが……","ENG":"If there's an incident that made us sure of that...","TWN":"確定她是制裁者的契機……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래요. 동물원에서 이송하던 반달곰이 탈출했던 사건! 기억하세요?","JPN":"動物園から移送中だった\\nツキノワグマが脱出した事件です！　覚えてますか？","ENG":"Oh, that's right. There was that time the black bear escaped from the zoo while being transferred! Remember that?","TWN":"對了，動物園移送亞洲黑熊的逃跑事件！你記得嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"언론에선 경찰이 곰을 마취시켜 사건을 해결한 걸로 알고 있지만......","JPN":"メディアでは警察がクマに麻酔銃を\\n撃って事件を解決したことになっていますが……","ENG":"The media reported it as if the cops drugged the bear to capture it...","TWN":"雖然媒體說是警察麻醉了黑熊，才解決事件的……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그게 전부는 아니에요.","JPN":"それがすべてではありません。","ENG":"But that's not all.","TWN":"但這不是事情的全部經過。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"시장에서 사람들을 습격하려던 곰을 얌전하게 만들었던 건 바로 하림이었거든요.","JPN":"市場で人々に襲いかかろうとしていた\\nクマをおとなしくさせたのはウサギなんです。","ENG":"It was actually Harim who calmed down the bear that was attacking people in the market.","TWN":"因為讓正要襲擊市場的熊安分下來的人，正是夏琳。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"쿠워어어어어!!!","JPN":"グオオオォ！！","ENG":"Rooooaar!","TWN":"吼吼吼吼吼吼！！"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"떽!","JPN":"ほらほら！","ENG":"Hey!","TWN":"站住！"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"자~ 착하지. 이런 곳에서 말썽부리면 안돼요.","JPN":"いい子でしょ？　こんな所で暴れちゃダメだよ！","ENG":"There, there. You shouldn't be causing trouble here.","TWN":"好～真乖。不可以在這種地方搗蛋喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"뀨우웅...... 꾸웅......","JPN":"クウゥーン……クゥン……","ENG":"*Whimper* *Groan*","TWN":"嗷嗷嗚……嗷嗚……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"옳지, 그래. 얌전히 있어야지.","JPN":"そうそう。おとなしくしてなきゃ！","ENG":"Good girl, yes. You need to behave.","TWN":"沒錯，做得很好。你得乖乖待著喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};